import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

/**
 * Seed 脚本
 *
 * 幂等性保证：所有 INSERT 使用 ON CONFLICT DO NOTHING / upsert，
 * 可重复执行而不会产生重复数据。
 *
 * 当 Prisma schema 最终的 IT Asset Management 模型就绪后，
 * 此脚本将使用 prisma.user.upsert() 等原生 upsert 方法。
 * 当前阶段使用原始 SQL 确保最小依赖。
 */

async function main() {
  console.log("Seeding database...");

  // ============================================================
  // Departments
  // ============================================================
  console.log("  Creating departments...");
  const departments = [
    { id: "dept-it", name: "信息技术部" },
    { id: "dept-engineering", name: "研发部" },
    { id: "dept-finance", name: "财务部" },
    { id: "dept-hr", name: "人力资源部" },
    { id: "dept-ops", name: "运营部" },
    { id: "dept-warehouse", name: "仓储部" },
    { id: "dept-exec", name: "管理层" },
  ];

  for (const dept of departments) {
    await prisma.$executeRawUnsafe(
      `INSERT INTO "Department" (id, name) VALUES ($1, $2) ON CONFLICT (id) DO NOTHING`,
      dept.id,
      dept.name
    );
  }

  // ============================================================
  // Users (6 个默认账号)
  // 密码统一为 "password" (bcrypt hash)
  // ============================================================
  console.log("  Creating users...");
  const bcrypt = await import("bcryptjs");
  const passwordHash = await bcrypt.hash("password", 10);

  const users = [
    { id: "user-admin", email: "admin@company.com", name: "管理员", role: "IT_ADMIN", deptId: "dept-it" },
    { id: "user-manager", email: "manager@company.com", name: "张经理", role: "MANAGER", deptId: "dept-engineering" },
    { id: "user-employee", email: "employee@company.com", name: "李员工", role: "EMPLOYEE", deptId: "dept-engineering" },
    { id: "user-executive", email: "executive@company.com", name: "王总", role: "EXECUTIVE", deptId: "dept-exec" },
    { id: "user-finance", email: "finance@company.com", name: "赵财务", role: "MANAGER", deptId: "dept-finance" },
    { id: "user-warehouse", email: "warehouse@company.com", name: "孙仓库", role: "MANAGER", deptId: "dept-warehouse" },
  ];

  for (const user of users) {
    await prisma.$executeRawUnsafe(
      `INSERT INTO "User" (id, email, "passwordHash", name, role, "deptId", status)
       VALUES ($1, $2, $3, $4, $5, $6, 'ACTIVE')
       ON CONFLICT (email) DO NOTHING`,
      user.id,
      user.email,
      passwordHash,
      user.name,
      user.role,
      user.deptId
    );
  }

  // ============================================================
  // 更新 Department 的 managerId
  // ============================================================
  console.log("  Updating department managers...");
  await prisma.$executeRawUnsafe(
    `UPDATE "Department" SET "managerId" = 'user-manager' WHERE id = 'dept-engineering'`
  );
  await prisma.$executeRawUnsafe(
    `UPDATE "Department" SET "managerId" = 'user-finance' WHERE id = 'dept-finance'`
  );
  await prisma.$executeRawUnsafe(
    `UPDATE "Department" SET "managerId" = 'user-warehouse' WHERE id = 'dept-warehouse'`
  );
  await prisma.$executeRawUnsafe(
    `UPDATE "Department" SET "managerId" = 'user-executive' WHERE id = 'dept-exec'`
  );

  console.log("Seed completed successfully.");
}

main()
  .catch((e) => {
    console.error("Seed failed:", e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
